import{_ as a,o as i,c as e,ai as t}from"./chunks/framework.BIXs0jTs.js";const l="/assets/preface-cover.Balx8Fq4.png",g=JSON.parse('{"title":"Claude Code 工作流","description":"","frontmatter":{"title":"Claude Code 工作流"},"headers":[],"relativePath":"10-claude-code/workflow.md","filePath":"10-claude-code/workflow.md","lastUpdated":null}'),n={name:"10-claude-code/workflow.md"};function o(h,s,p,d,r,c){return i(),e("div",null,[...s[0]||(s[0]=[t('<h1 id="第-3-章-把-claude-code-嵌入你的日常工作" tabindex="-1">第 3 章　把 Claude Code 嵌入你的日常工作 <a class="header-anchor" href="#第-3-章-把-claude-code-嵌入你的日常工作" aria-label="Permalink to &quot;第 3 章　把 Claude Code 嵌入你的日常工作&quot;">​</a></h1><p><img src="'+l+`" alt="日常工作流：从需求分析到代码交付"></p><p>了解了 Ask、Plan、Agent 和 Debug 四种模式后，下一个问题是：<strong>我该怎么把它们串起来，用到我每天的搬砖生活里？</strong></p><p>本章将从“环境搭建”开始，一步步带你构建一个基于 Claude Code 的高效开发工作流。我们的目标不是让你变成“只会写 Prompt 的人”，而是让你现有的工作流（Git、IDE、CI/CD）因为有了 AI 而变得更快、更稳。</p><h2 id="_3-1-搭建最小可用环境" tabindex="-1">3.1 搭建最小可用环境 <a class="header-anchor" href="#_3-1-搭建最小可用环境" aria-label="Permalink to &quot;3.1 搭建最小可用环境&quot;">​</a></h2><p>在正式开始之前，确保你的工程环境已经准备就绪。</p><h3 id="_3-1-1-忽略文件配置" tabindex="-1">3.1.1 忽略文件配置 <a class="header-anchor" href="#_3-1-1-忽略文件配置" aria-label="Permalink to &quot;3.1.1 忽略文件配置&quot;">​</a></h3><p>Claude Code 会读取你的项目文件，但有些文件（如 <code>package-lock.json</code>、巨型数据文件、敏感配置）是不应该被读取的。 虽然 Claude Code 会自动尊重 <code>.gitignore</code>，但你可能还需要额外的忽略规则。</p><p><strong>最佳实践</strong>：在项目根目录创建一个 <code>.claudeignore</code>（如果支持）或者确保 <code>.gitignore</code> 覆盖了以下内容：</p><ul><li><code>node_modules/</code></li><li><code>dist/</code> 或 <code>build/</code></li><li><code>.env</code> (包含密钥的文件)</li><li><code>*.log</code></li></ul><h3 id="_3-1-2-权限与安全边界" tabindex="-1">3.1.2 权限与安全边界 <a class="header-anchor" href="#_3-1-2-权限与安全边界" aria-label="Permalink to &quot;3.1.2 权限与安全边界&quot;">​</a></h3><p>Claude Code 在 Agent 模式下可以执行 shell 命令。为了安全起见：</p><ul><li><strong>不要在生产服务器上直接运行 Agent 模式</strong>，除非你非常清楚自己在做什么。</li><li>建议在 Docker 容器或本地开发环境中运行，确保持久化数据有备份。</li></ul><hr><h2 id="_3-2-日常开发中的使用模式" tabindex="-1">3.2 日常开发中的使用模式 <a class="header-anchor" href="#_3-2-日常开发中的使用模式" aria-label="Permalink to &quot;3.2 日常开发中的使用模式&quot;">​</a></h2><p>我们来看几个最常见的开发场景，以及 Claude Code 在其中的角色。</p><h3 id="_3-2-1-模式-a-作为-结对编程伙伴-the-pair-programmer" tabindex="-1">3.2.1 模式 A：作为“结对编程伙伴” (The Pair Programmer) <a class="header-anchor" href="#_3-2-1-模式-a-作为-结对编程伙伴-the-pair-programmer" aria-label="Permalink to &quot;3.2.1 模式 A：作为“结对编程伙伴” (The Pair Programmer)&quot;">​</a></h3><p>这是最自然的用法。你和 Claude Code 一起工作，你负责设计和审查，它负责实现细节。</p><p><strong>流程</strong>：</p><ol><li><strong>你</strong>：定义接口结构或写一段伪代码。</li><li><strong>Claude</strong>：补全具体实现。</li><li><strong>你</strong>：指出逻辑漏洞或风格问题。</li><li><strong>Claude</strong>：修正代码。</li></ol><p><strong>适用场景</strong>：编写工具函数、编写样板代码、编写单元测试。</p><h3 id="_3-2-2-模式-b-作为-初级架构师-the-junior-architect" tabindex="-1">3.2.2 模式 B：作为“初级架构师” (The Junior Architect) <a class="header-anchor" href="#_3-2-2-模式-b-作为-初级架构师-the-junior-architect" aria-label="Permalink to &quot;3.2.2 模式 B：作为“初级架构师” (The Junior Architect)&quot;">​</a></h3><p>当你需要进行模块重构或设计新功能时，Claude Code 可以帮你梳理思路。</p><p><strong>流程</strong>：</p><ol><li><strong>你</strong>：<code>claude plan &quot;我想把用户认证逻辑从 App.vue 抽离到独立的 composable 中&quot;</code>。</li><li><strong>Claude</strong>：分析现状，列出需要修改的文件（App.vue, login.ts, store.ts），并提示潜在风险。</li><li><strong>你</strong>：审查计划，确认无误。</li><li><strong>Claude</strong>：<code>claude &quot;开始执行上述计划&quot;</code>。</li></ol><p><strong>适用场景</strong>：中等规模的重构、模块拆分、技术栈迁移。</p><h3 id="_3-2-3-模式-c-作为-运维-救火队员-the-ops-firefighter" tabindex="-1">3.2.3 模式 C：作为“运维/救火队员” (The Ops/Firefighter) <a class="header-anchor" href="#_3-2-3-模式-c-作为-运维-救火队员-the-ops-firefighter" aria-label="Permalink to &quot;3.2.3 模式 C：作为“运维/救火队员” (The Ops/Firefighter)&quot;">​</a></h3><p>当系统报错或测试挂掉时，Claude Code 是最好的日志分析器。</p><p><strong>流程</strong>：</p><ol><li><strong>系统</strong>：抛出一大堆 traceback。</li><li><strong>你</strong>：<code>claude debug</code> 或直接粘贴错误日志。</li><li><strong>Claude</strong>：指出“第 42 行的变量未定义”，并检查上次 commit 的变动，发现是拼写错误。</li><li><strong>Claude</strong>：提出修复补丁。</li></ol><hr><h2 id="_3-3-典型工作流示例" tabindex="-1">3.3 典型工作流示例 <a class="header-anchor" href="#_3-3-典型工作流示例" aria-label="Permalink to &quot;3.3 典型工作流示例&quot;">​</a></h2><p>让我们通过三个具体的故事，看看这些模式是如何串联起来的。</p><h3 id="_3-3-1-故事一-测试驱动开发-tdd-的新玩法" tabindex="-1">3.3.1 故事一：测试驱动开发 (TDD) 的新玩法 <a class="header-anchor" href="#_3-3-1-故事一-测试驱动开发-tdd-的新玩法" aria-label="Permalink to &quot;3.3.1 故事一：测试驱动开发 (TDD) 的新玩法&quot;">​</a></h3><p><strong>传统 TDD</strong>：红（写失败测试） -&gt; 绿（写实现让测试通过） -&gt; 重构。 <strong>Claude TDD</strong>：</p><ol><li><strong>红</strong>：你创建一个测试文件 <code>user.test.ts</code>，写下测试用例：<div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">it</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;should calculate discount correctly&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, () </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  expect</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">calcDiscount</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;VIP&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)).</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">toBe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">80</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">});</span></span></code></pre></div></li><li><strong>Agent</strong>：你运行命令：<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;实现 calcDiscount 函数，使 user.test.ts 通过&quot;</span></span></code></pre></div></li><li><strong>绿</strong>：Claude 读取测试代码，实现函数逻辑，运行测试，直到变绿。</li><li><strong>重构</strong>：你审查代码，发现逻辑太啰嗦，于是说：<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;重构 calcDiscount，用策略模式优化 switch-case&quot;</span></span></code></pre></div></li></ol><h3 id="_3-3-2-故事二-遗留代码的-考古挖掘" tabindex="-1">3.3.2 故事二：遗留代码的“考古挖掘” <a class="header-anchor" href="#_3-3-2-故事二-遗留代码的-考古挖掘" aria-label="Permalink to &quot;3.3.2 故事二：遗留代码的“考古挖掘”&quot;">​</a></h3><p>你接手了一个 5 年前的 Python 项目，里面有一个 500 行的 <code>process_data</code> 函数，没人敢动。</p><ol><li><p><strong>Ask</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;阅读 process_data 函数，用中文解释它的主要步骤，并画一个流程图&quot;</span></span></code></pre></div><p>Claude 帮你理清了逻辑，你发现它其实只做了三件事：清洗、计算、入库。</p></li><li><p><strong>Plan</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;将 process_data 拆分为 clean_data, calc_logic, save_to_db 三个函数，保持原有逻辑不变&quot;</span></span></code></pre></div><p>Claude 列出拆分方案，你确认没问题。</p></li><li><p><strong>Agent</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;执行上述拆分，并确保现有测试（如果有的话）依然通过&quot;</span></span></code></pre></div></li></ol><h3 id="_3-3-3-故事三-修复难以复现的-bug" tabindex="-1">3.3.3 故事三：修复难以复现的 Bug <a class="header-anchor" href="#_3-3-3-故事三-修复难以复现的-bug" aria-label="Permalink to &quot;3.3.3 故事三：修复难以复现的 Bug&quot;">​</a></h3><p>线上偶尔报 <code>NullPointerException</code>，但本地很难复现。</p><ol><li><p><strong>Ask</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;根据这段 Sentry 日志（粘贴日志），分析可能导致空指针的原因&quot;</span></span></code></pre></div><p>Claude 提示：可能是 <code>user.profile</code> 在某些边缘情况下为空。</p></li><li><p><strong>Agent (写测试)</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;写一个复现脚本，模拟 user.profile 为空的情况，验证是否会报错&quot;</span></span></code></pre></div></li><li><p><strong>Debug</strong>： 运行复现脚本，果然报错。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;修复这个 Bug，添加空值检查&quot;</span></span></code></pre></div></li></ol><hr><h2 id="_3-4-效率小贴士" tabindex="-1">3.4 效率小贴士 <a class="header-anchor" href="#_3-4-效率小贴士" aria-label="Permalink to &quot;3.4 效率小贴士&quot;">​</a></h2><p>最后，分享几个让 Claude Code 更好用的小技巧：</p><ol><li><p><strong>使用 Alias (别名)</strong>： 在你的 shell 配置文件（<code>.zshrc</code> 或 <code>.bashrc</code>）里添加：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">alias</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> c</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;claude&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">alias</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ca</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;claude ask&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">alias</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> cp</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;claude plan&quot;</span></span></code></pre></div><p>这样你就可以用 <code>c &quot;fix bug&quot;</code> 快速调用了。</p></li><li><p><strong>保持 Commit 粒度</strong>： 尽量让 Claude Code 做完一个小任务（如修复一个函数）就提交一次 git commit。不要让它一次性改几十个文件，否则 Code Review 会变成噩梦。</p></li><li><p><strong>善用 <code>--print</code></strong>： 如果你只想看它生成的代码，不想让它自动写入文件，可以使用相关参数（视具体版本而定，通常有只输出不执行的选项）。</p></li></ol><p>通过这些工作流的组合，你会发现 Claude Code 不再是一个需要你“费力提问”的工具，而是一个自然融入你指尖的强大插件。</p>`,47)])])}const u=a(n,[["render",o]]);export{g as __pageData,u as default};
